int getFirst(vector<int> &numbers)
{
    return numbers[0]; // always exactly one operation, regardless of size
}

int sum(vector<int> &numbers)
{
    int total = 0;
    for (int i = 0; i < numbers.size(); i++) // runs once PER element
    {
        total += numbers[i];
    }
    return total;
}

void printAllPairs(vector<int> &numbers)
{
    for (int i = 0; i < numbers.size(); i++)
    {
        for (int j = 0; j < numbers.size(); j++) // a full inner loop, for EVERY outer step
        {
            cout << numbers[i] << "," << numbers[j] << " ";
        }
    }
}
